def svg_card(path,title,subtitle,chapter,index,kind):
 p=ROOT/path;p.parent.mkdir(parents=True,exist_ok=True)
 title=html.escape(title);subtitle=html.escape(subtitle);marks=['◉','≈','⚔','⛰','▥','⚓','⌂','◇','◆','◎'];acc=['#b88065','#8da09b','#a97264','#967b61','#7f9f9e','#a57a67','#8c7f9b','#6f9a8f','#b28c5b','#9d7463'][chapter-1]
 p.write_text(f'''<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 720 900" role="img" aria-label="{title}"><defs><linearGradient id="g" x2="1" y2="1"><stop stop-color="#070809"/><stop offset=".55" stop-color="#252627"/><stop offset="1" stop-color="#0e0707"/></linearGradient><radialGradient id="r"><stop stop-color="{acc}" stop-opacity=".5"/><stop offset="1" stop-color="{acc}" stop-opacity="0"/></radialGradient></defs><rect width="720" height="900" fill="url(#g)"/><circle cx="565" cy="180" r="285" fill="url(#r)"/><path d="M0 690 C140 610 275 735 430 650 S625 610 720 655 V900 H0Z" fill="#040506" opacity=".94"/><path d="M62 112 H658 M62 790 H658" stroke="{acc}" stroke-width="2" opacity=".85"/><text x="62" y="82" fill="{acc}" font-size="20" font-family="Arial" letter-spacing="4">BRONZE AGE COLLAPSE · {chapter:02d}</text><text x="560" y="365" text-anchor="middle" fill="{acc}" font-size="165" font-family="serif" opacity=".9">{marks[chapter-1]}</text><path d="M90 455 L220 400 L325 500 L445 430 L575 505 L660 452" fill="none" stroke="{acc}" stroke-width="7" opacity=".35"/><text x="62" y="654" fill="#fff8e9" font-size="42" font-family="Georgia">{title[:30]}</text><text x="62" y="710" fill="#d8d0c2" font-size="23" font-family="Arial">{subtitle[:52]}</text><text x="62" y="832" fill="{acc}" font-size="18" font-family="Arial" letter-spacing="3">{kind.upper()} · CODEX OF HISTORY · {index:02d}</text></svg>''',encoding='utf-8')

